### Render Lexical Rich Text Editor within a Payload Form (TypeScript)

Source: https://github.com/payloadcms/payload/blob/main/docs/rich-text/rendering-on-demand.mdx

This example demonstrates how to integrate the `RenderLexical` component into an existing Payload form. It uses `buildEditorState` to set an initial value and requires the `name` property to match the field name present in the form, alongside a `schemaPath` to resolve the field's schema.

```tsx
'use client'

import type { JSONFieldClientComponent } from 'payload'

import {
  buildEditorState,
  RenderLexical,
} from '@payloadcms/richtext-lexical/client'

import { lexicalFullyFeaturedSlug } from '../../slugs.js'

export const Component: JSONFieldClientComponent = (args) => {
  return (
    <RenderLexical
      field={{
        name: 'myFieldName' /* Make sure this matches the field name present in your form */,
      }}
      initialValue={buildEditorState<DefaultNodeTypes>({
        text: 'default value',
      })}
      schemaPath={`collection.${lexicalFullyFeaturedSlug}.richText`}
    />
  )
}
```
